#!/usr/bin/env node
/**
 * Regenerates src/data/identifier-status.generated.ts from the Unicode
 * Consortium's UTS #39 Identifier_Status data.
 *
 * Usage:
 *   node scripts/generate-identifier-status.mjs               # fetch /Public/security/latest/
 *   node scripts/generate-identifier-status.mjs --version 17.0.0
 *   node scripts/generate-identifier-status.mjs --file path/to/IdentifierStatus.txt
 *
 * The generated file is checked in; this script only needs to run when a new
 * Unicode security release ships. A scheduled CI job is the intended caller.
 *
 * IdentifierStatus.txt lists the ALLOWED characters — those Unicode considers
 * appropriate in identifiers. Everything absent from it is Restricted:
 * technical, obsolete or limited-use characters that have no business in
 * ordinary prose. That distinction is what separates "æ in a Danish surname"
 * from "IPA alpha standing in for a latin a".
 */
import { readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const args = process.argv.slice(2);
const getArg = (name) => {
  const i = args.indexOf(name);
  return i === -1 ? undefined : args[i + 1];
};

async function loadSource() {
  const file = getArg('--file');
  if (file) return readFileSync(file, 'utf8');
  const version = getArg('--version') ?? 'latest';
  const url = `https://www.unicode.org/Public/security/${version}/IdentifierStatus.txt`;
  const res = await fetch(url);
  if (!res.ok) throw new Error(`GET ${url} -> ${res.status}`);
  return res.text();
}

const source = await loadSource();

const versionMatch = source.match(/^#\s*Version:\s*(\S+)/m);
const dateMatch = source.match(/^#\s*Date:\s*([\d-]+)/m);
if (!versionMatch) throw new Error('No "# Version:" header in IdentifierStatus.txt');

// Each data line is: <cp> ; Allowed  or  <cp>..<cp> ; Allowed
const ranges = [];
for (const line of source.split('\n')) {
  const data = line.split('#')[0].trim();
  if (!data) continue;
  const [cps, status] = data.split(';').map((s) => s.trim());
  if (status !== 'Allowed' || !cps) continue;
  const [from, to] = cps.split('..');
  const start = parseInt(from, 16);
  const end = to === undefined ? start : parseInt(to, 16);
  if (!Number.isInteger(start) || !Number.isInteger(end) || end < start) {
    throw new Error(`Unparseable range: ${cps}`);
  }
  ranges.push([start, end]);
}
if (ranges.length < 500) {
  throw new Error(`Suspiciously few ranges (${ranges.length}) — refusing to write`);
}

ranges.sort((a, b) => a[0] - b[0]);
// Merge touching/overlapping ranges so the runtime binary search sees a
// strictly increasing, non-overlapping list.
const merged = [];
for (const [start, end] of ranges) {
  const last = merged[merged.length - 1];
  if (last && start <= last[1] + 1) last[1] = Math.max(last[1], end);
  else merged.push([start, end]);
}

// Packed as delta-encoded hex pairs: "<gap from previous end>.<length>", so the
// common case (a short range close to the last one) stays a couple of chars.
let cursor = 0;
const packed = merged
  .map(([start, end]) => {
    const entry = `${(start - cursor).toString(36)}.${(end - start).toString(36)}`;
    cursor = end;
    return entry;
  })
  .join(';');
const chunks = packed.match(/.{1,2000}/gs) ?? [];

const __dirname = dirname(fileURLToPath(import.meta.url));
const outPath = join(__dirname, '..', 'src', 'data', 'identifier-status.generated.ts');
mkdirSync(dirname(outPath), { recursive: true });

writeFileSync(
  outPath,
  `// AUTO-GENERATED by scripts/generate-identifier-status.mjs — DO NOT EDIT.
// Source: UTS #39 IdentifierStatus.txt (https://www.unicode.org/reports/tr39/)
// Ranges: ${merged.length} (Identifier_Status=Allowed; everything else is Restricted)

export const IDENTIFIER_STATUS_VERSION = '${versionMatch[1]}';
export const IDENTIFIER_STATUS_DATE = '${dateMatch?.[1] ?? 'unknown'}';

/** Delta-encoded base-36 "<gap>.<length>" pairs — see the generator. */
export const ALLOWED_RANGES_PACKED =
${chunks.map((c) => `  '${c}'`).join(' +\n')};
`,
);

console.log(`Wrote ${merged.length} allowed ranges (Unicode ${versionMatch[1]}) to ${outPath}`);
